import { PermitType, useERC20Permit } from "./useERC20Permit";
import useTransactionDeadline from "./useTransactionDeadline";
const REMOVE_V2_LIQUIDITY_PERMIT_INFO = {
    version: "1",
    name: "Uniswap V2",
    type: PermitType.AMOUNT
};
export function useV2LiquidityTokenPermit(liquidityAmount, spender) {
    const transactionDeadline = useTransactionDeadline();
    return useERC20Permit(liquidityAmount, spender, transactionDeadline, REMOVE_V2_LIQUIDITY_PERMIT_INFO);
}
